```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    mapping(address => uint256) public balances;

    event Buy(address indexed buyer, uint256 amount);
    event PriceChanged(uint256 newPrice);
    event Withdrawal(address indexed recipient, uint256 amount);

    bool private _mutex;

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    modifier noReentrancy() {
        require(!_mutex, "No reentrancy");
        _mutex = true;
        _;
        _mutex = false;
    }

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
    }

    function buy(uint256 amount) external payable {
        require(!saleEnded, "Sale has ended");
        require(amount > 0 && amount <= 10, "Invalid amount");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");

        uint256 totalPrice = amount * price;
        require(msg.value >= totalPrice, "Insufficient payment");

        balances[msg.sender] += amount;
        totalMinted += amount;

        if (totalMinted >= maxSupply) {
            saleEnded = true;
        }

        emit Buy(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function withdraw() external onlyOwner noReentrancy {
        uint256 amount = address(this).balance;
        payable(owner).transfer(amount);
        emit Withdrawal(owner, amount);
    }
}
